SELECT * FROM (SELECT TRY_CAST("YEAR" AS INTEGER) AS year, TRY_CAST("MONTH" AS INTEGER) AS month, make_date(TRY_CAST("YEAR" AS INTEGER), TRY_CAST("MONTH" AS INTEGER), 1) AS date, NULLIF("STATE_NAME", '') AS state_name, NULLIF("STATE_CODE", '') AS state_code, NULLIF("NOTE", '') AS note, TRY_CAST("CO2_QTY_TONNES" AS DOUBLE) AS co2_qty_tonnes, TRY_CAST("TF" AS DOUBLE) AS tf FROM "eurocontrol-co2-emmissions-by-state") WHERE date IS NOT NULL
